struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Create a binary_stream object from the buffer
    hexi::binary_stream stream(const_cast<std::span<uint8_t>&>(buffer));

    // Read message_type using operator>>
    uint16_t message_type;
    stream >> message_type;

    // Read body_length using operator>>
    uint32_t body_length;
    stream >> body_length;

    // Skip the body_data using skip()
    stream.skip(body_length);

    // Read footer using operator>>
    uint32_t footer;
    stream >> footer;

    // Return the MessageHeader struct with the read values
    return MessageHeader{message_type, body_length, footer};
}
```

**Explanation:**

1. **Creating binary_stream**: The `binary_stream` object is created from the input buffer using the constructor that takes a buffer reference.

