    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Check available space using buffer_adaptor's size() method
    auto available_space = adaptor.size();

    // Calculate total data size: sizeof(header) + items.size() * sizeof(uint32_t)
    auto total_data_size = sizeof(header) + items.size() * sizeof(uint32_t);

    // Compare available space with required space
    if (available_space < total_data_size) {
        return false; // Insufficient space
    }

    // Get write pointer using buffer_adaptor's write_ptr() method
    auto* write_pointer = adaptor.write_ptr();

    // Write header using pointer arithmetic
    std::memcpy(write_pointer, &header, sizeof(header));
    write_pointer += sizeof(header);

    // Use binary_stream to write the container
    hexi::binary_stream<std::vector<uint8_t>> stream(buffer);
    stream.write_container(items);

    return true; // Write successful
}
