using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Get the total bytes written before encoding
    auto start = writer.total_write();
    // Use varint_encode to encode the value
    varint_encode(writer, value);
    // Return the number of bytes written during encoding
    return writer.total_write() - start;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    // Use varint_decode to decode the value from the reader
    return varint_decode<T>(reader);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::byte> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    // Create a binary_stream_writer and binary_stream_reader using the buffer_adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Use the writer to encode the original value
    encode_varint(writer, original_value);

    // Use the reader to decode the value
    T decoded_value = decode_varint<T>(reader);

    // Compare the decoded value with the original and return the result
    return decoded_value == original_value;
}
